example:
.modal { position: fixed; inset: 0; }
.card { position: relative; }
.badge { position: absolute; top: 8px; right: 8px; }

html { font-size: 16px; }
p { margin-bottom: 1rem; }
.btn { padding: 0.5em 1em; font-size: 14px; }

@keyframes fade-in { from { opacity: 0 } to { opacity: 1 } }
.reveal { animation: fade-in linear both;
  animation-timeline: view(); animation-range: entry 0% cover 40%; }

.container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

.child {
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
}

.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
}

.container {
  display: grid;
  gap: 1rem;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
}

.text {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.modal {
  position: fixed;
  inset: 0;
  display: grid;
  place-items: center;
}
.modal__panel { transform: translate(0); }

.tip { position: relative; }
.tip__pop {
  position: absolute; bottom: 100%;
  opacity: 0; pointer-events: none;
}
.tip:hover .tip__pop { opacity: 1; }

.skeleton {
  border-radius: 8px;
  background: linear-gradient(90deg, #eee 25%, #f5f5f5 50%, #eee 75%);
  background-size: 200% 100%;
  animation: shimmer 1.2s infinite;
}
